const lots = $input.item.json.lots;

// Sort: prioritize lots with a real estimate (not BuyNow)
// Ratio: total_price / estimate — smaller is better
const sorted = [...lots].sort((a, b) => {
  const getRatio = l => {
    if (l.estimate > 0) return l.total_price / l.estimate;  // real estimate
    return 0.99;  // no estimate -> sort neutrally
  };
  return getRatio(a) - getRatio(b);
});

// Send the top 15 to Perplexity + Claude
const top = sorted.slice(0, 15);
console.log('Lots total:', lots.length, '| To Perplexity/Claude:', top.length);

if (top.length === 0) return [];
return top.map(lot => ({ json: lot }));

const d = $input.item.json;

const estInfo = d.estimate > 0
  ? 'Auction estimate (expert appraisal): ' + d.estimate + '\u20ac\n'
  : '';
const buyNowInfo = d.buy_now_eur > 0
  ? 'BuyNow price (NOT a market value, usually inflated): ' + d.buy_now_eur + '\u20ac\n'
  : '';
const shippingInfo = d.shipping_eur > 0 ? 'Shipping to destination: ' + d.shipping_eur + '\u20ac\n' : '';

const prompt =
  'Determine the current market value from real comparable sales (eBay sold, auction houses, marketplace shops, last 2 years).\n\n' +
  'Title: ' + d.title + '\n' +
  'Category: ' + d.category + '\n' +
  (d.description ? 'Description: ' + d.description + '\n' : '') +
  estInfo + buyNowInfo +
  'Current bid: ' + d.current_price + '\u20ac (total price incl. fees: ' + d.total_price + '\u20ac)\n' +
  shippingInfo + '\n' +
  'Answer ONLY as JSON (no markdown):\n' +
  '{"market_value_eur": 150, "comparison_link": "https://...", "market_info": "max 50 words: price comparisons with sources"}\n' +
  'market_value_eur: 0 if no comparison found. comparison_link: direct link or null.';

return {
  json: {
    ...d,
    _body: {
      model: 'sonar',
      messages: [{ role: 'user', content: prompt }],
      max_tokens: 200
    }
  }
};

const response = $input.item.json;
const lot = $('Perplexity Body').item.json;

const content = response.choices?.[0]?.message?.content || '{}';
let market = {};
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  market = JSON.parse(match ? match[0] : cleaned);
} catch(e) {
  market = { market_value_eur: 0, comparison_link: null, market_info: '' };
}

const marketValue = Number(market.market_value_eur) || 0;
const ratio = marketValue > 0 ? lot.total_price / marketValue : null;
const link = (typeof market.comparison_link === 'string' && market.comparison_link.startsWith('http'))
  ? market.comparison_link : null;

return {
  json: {
    ...lot,
    market_value_eur: marketValue,
    comparison_link: link,
    deal_ratio: ratio,
    market_info: String(market.market_info || '')
  }
};

const d = $input.item.json;

// No market value -> request a minimal answer
const hasMarketValue = d.market_value_eur > 0;

const marketValueInfo = hasMarketValue
  ? 'Market value per research: ' + d.market_value_eur + '\u20ac' +
    (d.comparison_link ? ' | source: ' + d.comparison_link : '') +
    (d.market_info ? '\n' + d.market_info : '')
  : 'Market value: NOT DETERMINED — no comparison found';

const dealInfo = hasMarketValue
  ? 'Deal: total price ' + d.total_price + '\u20ac = ' + Math.round(d.deal_ratio * 100) + '% of market value'
  : '';

const estInfo = d.estimate > 0 ? 'Auction estimate: ' + d.estimate + '\u20ac\n' : '';
const buyNowInfo = d.buy_now_eur > 0 ? 'BuyNow (inflated, not a reference): ' + d.buy_now_eur + '\u20ac\n' : '';
const shippingInfo = d.shipping_eur > 0 ? 'Shipping to destination: ' + d.shipping_eur + '\u20ac\n' : 'Shipping: unknown\n';

const ratingScale = hasMarketValue
  ? 'Rating scale (total price vs. market value):\n' +
    '- Once-in-a-century: <10% | Sensational: 10-20% | Exceptional deal: 20-35%\n' +
    '- Very good bargain: 35-50% | Good bargain: 50-65%\n' +
    '- Offer: 65-80% | Solid offer: 80-105% | No bargain: >105%'
  : 'No market value known -> rate as "No bargain" or "Solid offer" based on estimate/description.';

const tokenHint = hasMarketValue
  ? 'Reasoning: max 60 words. Risks: max 25 words.'
  : 'No market value -> rating: short (max 20 words), reasoning: max 30 words, risks: empty.';

const prompt =
  'Rate this auction lot.\n\n' +
  'Title: ' + d.title + '\n' +
  'Category: ' + d.category + '\n' +
  'Description: ' + d.description + '\n' +
  'Bid: ' + d.current_price + '\u20ac + fee ' + d.platform_fee + '\u20ac = total ' + d.total_price + '\u20ac\n' +
  shippingInfo + estInfo + buyNowInfo +
  marketValueInfo + '\n' + dealInfo + '\n' +
  'Time left: ' + d.time_left_h + 'h\n\n' +
  ratingScale + '\n' + tokenHint + '\n\n' +
  'Answer ONLY as JSON without markdown:\n' +
  '{"rating":"...","reasoning":"...","risks":"..."}';

return {
  json: {
    auction_id: d.auction_id,
    title: d.title,
    description: d.description,
    category: d.category,
    current_price: d.current_price,
    estimate: d.estimate,
    buy_now_eur: d.buy_now_eur || 0,
    market_value_eur: d.market_value_eur,
    comparison_link: d.comparison_link,
    market_info: d.market_info,
    platform_fee: d.platform_fee,
    total_price: d.total_price,
    shipping_eur: d.shipping_eur || 0,
    deal_ratio: d.deal_ratio,
    time_left_h: d.time_left_h,
    closes_at: d.closes_at || null,
    link: d.link,
    _body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: hasMarketValue ? 450 : 200,
      messages: [{ role: 'user', content: prompt }]
    }
  }
};

const response = $input.item.json;
const lot = $('Claude Body').item.json;

const content = response.content?.[0]?.text || '{}';
let rating = {};
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  rating = JSON.parse(cleaned);
} catch(e) {
  rating = {
    rating: 'Solid offer',
    reasoning: 'Automatic rating not possible.',
    risks: 'Manual review recommended.'
  };
}

const ratingMap = {
  'Once-in-a-century': '\ud83d\udc8e Once-in-a-century',
  'Sensational': '\ud83d\udd25\ud83d\udd25 Sensational',
  'Exceptional deal': '\ud83d\udd25 Exceptional deal',
  'Very good bargain': '\u2b50\u2b50\u2b50 Very good bargain',
  'Good bargain': '\u2b50\u2b50 Good bargain',
  'Offer': '\u2b50 Offer',
  'Solid offer': '\u2705 Solid offer',
  'No bargain': '\u274c No bargain'
};

const marketText = lot.market_value_eur > 0
  ? 'Market value: ' + lot.market_value_eur + '\u20ac | Deal: ' + Math.round((lot.deal_ratio || 0) * 100) + '% of market value' +
    (lot.market_info ? '\n' + lot.market_info : '') +
    (lot.comparison_link ? '\nComparison: ' + lot.comparison_link : '')
  : 'No market value determined.' + (lot.market_info ? '\n' + lot.market_info : '');

return {
  json: {
    auction_id: lot.auction_id,
    title: lot.title,
    description: lot.description,
    category: lot.category,
    current_price: lot.current_price,
    estimate: lot.estimate,
    market_value_eur: lot.market_value_eur,
    platform_fee: lot.platform_fee,
    total_price: lot.total_price,
    shipping_eur: lot.shipping_eur || 0,
    time_left_h: lot.time_left_h,
    closes_at: lot.closes_at || null,
    link: lot.link,
    market_research: marketText,
    rating_notion: ratingMap[rating.rating] || '\u2705 Solid offer',
    reasoning: String(rating.reasoning || 'No reasoning').substring(0, 2000),
    risks: String(rating.risks || 'No risks identified').substring(0, 2000)
  }
};

const notionResponse = $input.item.json;
const lot = $('Extract Rating').item.json;

const results = notionResponse.results || [];
const exists = results.length > 0;
const pageId = exists ? results[0].id : null;

return {
  json: {
    ...lot,
    notion_exists: exists,
    notion_page_id: pageId
  }
};

const d = $input.item.json;
const props = {
  'Title': { title: [{ text: { content: d.title } }] },
  'Current Price (\u20ac)': { number: d.current_price },
  'Platform Fee (\u20ac)': { number: d.platform_fee },
  'Total Price (\u20ac)': { number: d.total_price },
  'Estimate (\u20ac)': { number: d.estimate || 0 },
  'BuyNow (\u20ac)': { number: d.buy_now_eur || 0 },
  'Market Value (\u20ac)': { number: d.market_value_eur || 0 },
  'Shipping (\u20ac)': { number: d.shipping_eur || 0 },
  'Rating': { select: { name: d.rating_notion } },
  'Reasoning': { rich_text: [{ text: { content: d.reasoning } }] },
  'Risks': { rich_text: [{ text: { content: d.risks } }] },
  'Market Comparison': { rich_text: [{ text: { content: d.market_research } }] },
  'Link': { url: d.link }
};
if (d.closes_at) props['Closes at'] = { date: { start: d.closes_at } };
return {
  json: {
    notion_page_id: d.notion_page_id,
    _body: { properties: props }
  }
};

const d = $input.item.json;
const props = {
  'Title': { title: [{ text: { content: d.title } }] },
  'Auction_ID': { rich_text: [{ text: { content: d.auction_id } }] },
  'Category': { select: { name: d.category } },
  'Current Price (\u20ac)': { number: d.current_price },
  'Platform Fee (\u20ac)': { number: d.platform_fee },
  'Total Price (\u20ac)': { number: d.total_price },
  'Estimate (\u20ac)': { number: d.estimate || 0 },
  'BuyNow (\u20ac)': { number: d.buy_now_eur || 0 },
  'Market Value (\u20ac)': { number: d.market_value_eur || 0 },
  'Shipping (\u20ac)': { number: d.shipping_eur || 0 },
  'Rating': { select: { name: d.rating_notion } },
  'Reasoning': { rich_text: [{ text: { content: d.reasoning } }] },
  'Risks': { rich_text: [{ text: { content: d.risks } }] },
  'Market Comparison': { rich_text: [{ text: { content: d.market_research } }] },
  'Link': { url: d.link }
};
if (d.closes_at) props['Closes at'] = { date: { start: d.closes_at } };
return {
  json: {
    _body: {
      parent: { database_id: $env.NOTION_DB_ID },
      properties: props
    }
  }
};
